/// REGISTER_QUERY — read the derivation tree.
pub fn register_query(entity: &mut Entity, payload: &str) -> String {
    let register_id = payload.trim();
    if register_id.is_empty() {
        // No ID: list all register items
        let items = entity.register.list();
        let list: Vec<String> = items.iter().map(|item| {
            let type_str = match item.item_type {
                RegisterType::Axiom => "axiom",
                RegisterType::Theorem => "theorem",
                RegisterType::Definition => "definition",
                RegisterType::Observation => "observation",
                RegisterType::Crystallized => "crystallized",
            };
            format!("{{\"id\":\"{}\",\"type\":\"{}\",\"locked_at_k\":{},\"receipt_hash\":\"{}\",\"depends_on\":{},\"content_size\":{}}}",
                item.id, type_str, item.locked_at_k,
                item.receipt_hash.iter().map(|b| format!("{b:02x}")).collect::<String>(),
                format!("[{}]", item.depends_on.iter().map(|d| format!("\"{}\"", d)).collect::<Vec<_>>().join(",")),
                item.content.len())
        }).collect();
        format!("{{\"register_items\":[{}],\"count\":{}}}\n", list.join(","), items.len())
    } else if let Some(item) = entity.register.query(register_id) {
        let content_str = String::from_utf8_lossy(&item.content);
        let escaped = content_str.replace('\\', "\\\\")
            .replace('"', "\\\"")
            .replace('\n', "\\n")
            .replace('\r', "\\r")
            .replace('\t', "\\t");
        let type_str = match item.item_type {
            RegisterType::Axiom => "axiom",
            RegisterType::Theorem => "theorem",
            RegisterType::Definition => "definition",
            RegisterType::Observation => "observation",
            RegisterType::Crystallized => "crystallized",
        };
        let deps_json = format!("[{}]", item.depends_on.iter()
            .map(|d| format!("\"{}\"", d)).collect::<Vec<_>>().join(","));
        format!(
            "{{\"id\":\"{}\",\"type\":\"{}\",\"depends_on\":{},\"content\":\"{}\",\"receipt_hash\":\"{}\",\"locked_at_k\":{},\"supersedes\":{},\"verified\":{}}}\n",
            item.id, type_str, deps_json, escaped,
            item.receipt_hash.iter().map(|b| format!("{b:02x}")).collect::<String>(),
            item.locked_at_k,
            item.supersedes.as_ref().map(|s| format!("\"{}\"", s)).unwrap_or_else(|| "null".to_string()),
            item.verify(),
        )
    } else {
        format!("{{\"error\":\"register item not found\",\"id\":\"{}\"}}\n", register_id)
    }
}

/// REGISTER_LOCK — write to the derivation tree.
pub fn register_lock(entity: &mut Entity, payload: &str) -> String {
    if !payload.trim().is_empty() {
        let v: serde_json::Value = serde_json::from_str(payload).unwrap_or_default();
        let id = v.get("id").and_then(|s| s.as_str()).unwrap_or("");
        let content = v.get("content").and_then(|s| s.as_str()).unwrap_or("");
        let type_str = v.get("type").and_then(|s| s.as_str()).unwrap_or("observation");
        let supersedes = v.get("supersedes").and_then(|s| s.as_str());
        let deps: Vec<&str> = v.get("depends_on")
            .and_then(|a| a.as_array())
            .map(|arr| arr.iter().filter_map(|v| v.as_str()).collect())
            .unwrap_or_default();

        let item_type = match type_str {
            "axiom" => RegisterType::Axiom,
            "theorem" => RegisterType::Theorem,
            "definition" => RegisterType::Definition,
            _ => RegisterType::Observation,
        };

        if id.is_empty() || content.is_empty() {
            "{\"error\":\"id and content required\"}\n".to_string()
        } else {
            let k = entity.k_index as u64;
            let item = saios_kernel_v2::register::RegisterItem::new(
                id, item_type, deps, content.as_bytes(), k, supersedes,
            );
            let receipt_hash = item.receipt_hash;
            match entity.register.lock(item) {
                Ok(hash) => {
                    // Persist RegisterReceipt to chain
                    let tip = if entity.chain.len() > 0 {
                        entity.chain.read_at(entity.chain.len() - 1)
                            .map(|r| r.receipt_hash)
                            .unwrap_or([0u8; 32])
                    } else { [0u8; 32] };
                    let _reg_receipt = saios_kernel_v2::ledger::RegisterReceipt::new(
                        &tip, id, &receipt_hash, k, supersedes, content.len() as u32,
                    );
                    let t_k = Q::one();
                    let rcf = compute_rcf_hash(&entity.delta);
                    entity.k_index = entity.k_index.saturating_add(1);
                    entity.trajectory.observe(coherence_functional(&entity.delta));
                    let chain_receipt = saios_kernel_v2::ledger::MeshReceipt::build(
                        &rcf, &t_k, entity.entity_id,
                        entity.k_index as u64, &_reg_receipt.receipt_id,
                        saios_kernel_v2::constants::DISC_NORMAL,
                        0, entity.sluice_state.enc_u8(), None,
                    );
                    let _ = entity.chain.append(&chain_receipt);

                    format!(
                        "{{\"locked\":true,\"id\":\"{}\",\"type\":\"{}\",\"receipt_hash\":\"{}\",\"k_index\":{}}}\n",
                        id, type_str,
                        hash.iter().map(|b| format!("{b:02x}")).collect::<String>(),
                        entity.k_index,
                    )
                }
                Err(e) => format!("{{\"error\":\"{}\"}}\n", e),
            }
        }
    } else {
        "{\"error\":\"payload required\"}\n".to_string()
    }
}
